按 bit 读写文件需要使用 bit 操作，C语言中可以使用 `fread()` 函数和 `fwrite()` 函数进行读写。通常情况下，按 bit 读写文件时，可以把数据按位存储到一个字节中，这样读写的时候就可以方便地对每一位进行操作。

以下是按 bit 读写文件的示例代码，这里以读写 8 位数据为例：

```c
#include <stdio.h>
#include <stdlib.h>

int main() {
    // 写入文件
    FILE *fp = fopen("bit_file.bin", "wb");
    unsigned char data = 0b10101010;
    fwrite(&data, sizeof(unsigned char), 1, fp);
    fclose(fp);

    // 读取文件
    fp = fopen("bit_file.bin", "rb");
    unsigned char read_data = 0;
    fread(&read_data, sizeof(unsigned char), 1, fp);
    fclose(fp);

    // 按位输出读取的数据
    printf("%d %d %d %d %d %d %d %d\n",
           (read_data >> 7) & 0x01,
           (read_data >> 6) & 0x01,
           (read_data >> 5) & 0x01,
           (read_data >> 4) & 0x01,
           (read_data >> 3) & 0x01,
           (read_data >> 2) & 0x01,
           (read_data >> 1) & 0x01,
           read_data & 0x01
           );

   return 0;
}
```

按 byte 读写文件可以使用 `fread()` 函数和 `fwrite()` 函数进行读写。假设要读取一个二进制文件，可以按以下方式读取：

```c
#include <stdio.h>
#include <stdlib.h>

int main() {
    FILE *fp = fopen("byte_file.bin", "rb");
    unsigned char *buf = malloc(sizeof(unsigned char) * 1024);
    size_t read_size = fread(buf, sizeof(unsigned char), 1024, fp);
    fclose(fp);

    printf("read %zu bytes from byte_file.bin\n", read_size);
    free(buf);

    return 0;
}
```

写入的方式与上述代码相同。

按 4 字节读写文件也可以使用 `fread()` 函数和 `fwrite()` 函数进行读写。但是需要注意在字节序的问题，如果读取的文件中的数据是按照小端模式存储的话，就需要将读取到的数据进行反转。以下是一个按 4 字节读写文件的示例：

```c
#include <stdio.h>
#include <stdlib.h>

int main() {
    FILE *fp = fopen("4byte_file.bin", "rb");
    unsigned int *buf = malloc(sizeof(unsigned int) * 1024);
    size_t read_size = fread(buf, sizeof(unsigned int), 1024, fp);
    fclose(fp);

    // 将读取到的数据进行反转
    for (size_t i = 0; i < read_size; i++) {
        buf[i] = ((buf[i] >> 24) & 0xFF) |
                 ((buf[i] >> 8) & 0xFF00) |
                 ((buf[i] << 8) & 0xFF0000) |
                 ((buf[i] << 24) & 0xFF000000);
    }

    printf("read %zu 4-bytes from 4byte_file.bin\n", read_size);
    free(buf);

    return 0;
}
```

变长读写文件的接口可以根据实际需求进行设计。可以使用 C语言 的指针和内存分配函数 `malloc()` 来动态分配内存空间，读取变长数据时可以先读取一定长度的数据，然后根据数据中所包含的信息，再进行下一次读取。对于写入变长数据，可以先计算数据的长度，然后再进行写入。以下是一个简单的变长读写接口的示例代码：

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void write_varlen_data(FILE *fp, const void *data, size_t len) {
    fwrite(&len, sizeof(size_t), 1, fp); // 先写入数据的长度
    fwrite(data, sizeof(char), len, fp); // 再写入数据
}

void read_varlen_data(FILE *fp, void **data, size_t *len) {
    fread(len, sizeof(size_t), 1, fp); // 先读入数据的长度

    *data = malloc(*len); // 动态分配内存空间
    fread(*data, sizeof(char), *len, fp); // 读入数据
}

int main() {
    // 写入变长数据
    FILE *fp = fopen("varlen_file.bin", "wb");
    const char *data = "hello, world!";
    size_t len = strlen(data);
    write_varlen_data(fp, data, len);
    fclose(fp);

    // 读取变长数据
    fp = fopen("varlen_file.bin", "rb");
    char *read_data = NULL;
    size_t read_len = 0;
    read_varlen_data(fp, (void **)&read_data, &read_len);
    fclose(fp);

    printf("read data with length %zu: %s\n", read_len, read_data);

    free(read_data);

    return 0;
}
```

